SELECT [Purch_ Rcpt_ Header].[Posting Date], Item.[Trademark Code], Item.[Season Code], Sum(Val([Purch_ Rcpt_ Line.no_ of pairs])) AS PairsReceived, [Purchase Line].[Document No_], [Purchase Line].[Line No_], [Purch_ Rcpt_ Line].Type, Vendor.Name, [datalimite] AS dataGiacenza
FROM ((([Purch_ Rcpt_ Line] INNER JOIN ([Purchase Line] INNER JOIN [Purchase Header] ON [Purchase Line].[Document No_] = [Purchase Header].No_) ON ([Purch_ Rcpt_ Line].[Order Line No_] = [Purchase Line].[Line No_]) AND ([Purch_ Rcpt_ Line].[Order No_] = [Purchase Line].[Document No_])) INNER JOIN Item ON [Purch_ Rcpt_ Line].No_ = Item.No_) INNER JOIN [Purch_ Rcpt_ Header] ON [Purch_ Rcpt_ Line].[Document No_] = [Purch_ Rcpt_ Header].No_) INNER JOIN Vendor ON [Purchase Header].[Buy-from Vendor No_] = Vendor.No_
GROUP BY [Purch_ Rcpt_ Header].[Posting Date], Item.[Trademark Code], Item.[Season Code], [Purchase Line].[Document No_], [Purchase Line].[Line No_], [Purch_ Rcpt_ Line].Type, Vendor.Name, [datalimite]
HAVING ((([Purch_ Rcpt_ Header].[Posting Date])<=[datalimite]) AND ((Item.[Season Code])=[stagione]) AND ((Sum(Val([Purch_ Rcpt_ Line.no_ of pairs])))<>0) AND (([Purch_ Rcpt_ Line].Type)=19 Or ([Purch_ Rcpt_ Line].Type)=20));

